const stocks = $input.all();
const quantities = $("Get the Product Id").all();

const updatedItems = stocks.map((stock, index) => {
  const quantity = quantities[index]?.json?.quantity || 0;
  const total = stock?.json?.Stocks + quantity;
  return { ...stock.json, total };
});

return updatedItems;

